                    <th className="text-center px-1">🛡️</th>
                    <th className="text-center px-1">🧱</th>
                    <th className="text-center px-1">🧤</th>
                  </tr>
                </thead>
                <tbody>
                  {playerStats.map((ps: any) => (
                    <tr key={ps.id} className="border-b border-[var(--border)]/50 hover:bg-[var(--surface-alt)] transition-colors">
