-- Migration for Phase 4 (Football Engine)
-- Replaces the stub `rpc_process_football` with the full implementation

CREATE OR REPLACE FUNCTION public.rpc_process_football(
  p_match_id UUID,
  p_type TEXT,
  p_payload JSONB
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_state JSONB;
  v_team TEXT;
  v_period TEXT;
  v_is_paused BOOLEAN;

  -- Stats placeholders
  v_team_stats JSONB;
  v_goals INT;
  v_corners INT;
  v_fouls INT;
  v_yellows INT;
  v_reds INT;
  v_offsides INT;
  v_shots_on INT;
  v_shots_off INT;

  -- Clock placeholders
  v_clock_running BOOLEAN;
  v_last_start_time TEXT;
  v_elapsed_seconds INT;
BEGIN
  -- 1. Lock and load current State
  SELECT state, is_paused INTO v_state, v_is_paused
  FROM public.ls_match_state
  WHERE match_id = p_match_id
  FOR UPDATE;

  -- 2. Initialize state if NULL
  IF v_state IS NULL OR v_state = 'null'::jsonb THEN
    v_state := '{
      "period": "first_half",
      "status": "scheduled",
      "clock_running": false,
      "elapsed_seconds": 0,
      "last_clock_start_time": null,
      "added_extra_time_minutes": 0,
      "team_a_stats": {
        "goals": 0, "corners": 0, "fouls": 0, "yellow_cards": 0, "red_cards": 0, 
        "offsides": 0, "shots_on_target": 0, "shots_off_target": 0
      },
      "team_b_stats": {
        "goals": 0, "corners": 0, "fouls": 0, "yellow_cards": 0, "red_cards": 0, 
        "offsides": 0, "shots_on_target": 0, "shots_off_target": 0
      }
    }'::jsonb;
  END IF;

  -- Extract common properties from payload
  v_team := p_payload->>'team'; -- 'team_a' or 'team_b'

  -- Extract Clocks
  v_clock_running := (v_state->>'clock_running')::boolean;
  v_last_start_time := v_state->>'last_clock_start_time';
  v_elapsed_seconds := COALESCE((v_state->>'elapsed_seconds')::int, 0);

  ---------------------------------------------------------------------------
  -- 3. Match Clock / Period Core Logic
  ---------------------------------------------------------------------------
  IF p_type = 'match_start' OR p_type = 'match_resume' THEN
    IF v_clock_running = false THEN
      v_state := jsonb_set(v_state, '{clock_running}', 'true'::jsonb);
      v_state := jsonb_set(v_state, '{last_clock_start_time}', to_jsonb(now()::text));

      IF p_type = 'match_start' AND (v_state->>'status') = 'scheduled' THEN
         v_state := jsonb_set(v_state, '{status}', '"live"'::jsonb);
      END IF;
    END IF;

  ELSIF p_type = 'match_pause' OR p_type = 'half_time' OR p_type = 'full_time' THEN
    IF v_clock_running = true THEN
      -- Calculate drift
      v_elapsed_seconds := v_elapsed_seconds + EXTRACT(EPOCH FROM (now() - (v_last_start_time)::timestamp))::int;

      -- Update state with new settled elapsed seconds
      v_state := jsonb_set(v_state, '{clock_running}', 'false'::jsonb);
      v_state := jsonb_set(v_state, '{elapsed_seconds}', to_jsonb(v_elapsed_seconds));
      v_state := jsonb_set(v_state, '{last_clock_start_time}', 'null'::jsonb);
    END IF;

    -- Handle Status changes based on Period events
    IF p_type = 'half_time' THEN
       v_state := jsonb_set(v_state, '{period}', '"half_time"'::jsonb);
    ELSIF p_type = 'full_time' THEN
       v_state := jsonb_set(v_state, '{period}', '"full_time"'::jsonb);
       v_state := jsonb_set(v_state, '{status}', '"completed"'::jsonb);
    END IF;

  ELSIF p_type = 'extra_time_added' THEN
     v_state := jsonb_set(
       v_state, 
       '{added_extra_time_minutes}', 
       to_jsonb(COALESCE((p_payload->>'extra_minutes')::int, 0))
     );

  ---------------------------------------------------------------------------
  -- 4. In-game events that augment TEAM STATS
  ---------------------------------------------------------------------------
  ELSIF v_team IS NOT NULL AND v_team IN ('team_a', 'team_b') THEN

    -- Extract the correct team stats block
    IF v_team = 'team_a' THEN
      v_team_stats := v_state->'team_a_stats';
    ELSE
      v_team_stats := v_state->'team_b_stats';
    END IF;

    -- Extract specific counters
    v_goals := COALESCE((v_team_stats->>'goals')::int, 0);
    v_corners := COALESCE((v_team_stats->>'corners')::int, 0);
    v_fouls := COALESCE((v_team_stats->>'fouls')::int, 0);
    v_yellows := COALESCE((v_team_stats->>'yellow_cards')::int, 0);
    v_reds := COALESCE((v_team_stats->>'red_cards')::int, 0);
    v_offsides := COALESCE((v_team_stats->>'offsides')::int, 0);
    v_shots_on := COALESCE((v_team_stats->>'shots_on_target')::int, 0);
    v_shots_off := COALESCE((v_team_stats->>'shots_off_target')::int, 0);

    -- Apply changes
    IF p_type IN ('goal', 'penalty_goal') THEN
      v_goals := v_goals + 1;
      v_shots_on := v_shots_on + 1; -- goals implicitly count as shots on target
    ELSIF p_type = 'own_goal' THEN
      -- If team_a commits own goal, team_b gets point, but team_a gets stat penalty?
      -- For simplicity, standard system usually credits 'team' payload as the SCORING team.
      -- E.g. If payload team='team_a', team A scores, regardless of who kicked it in.
      v_goals := v_goals + 1;
    ELSIF p_type = 'corner' THEN
      v_corners := v_corners + 1;
    ELSIF p_type = 'foul' THEN
      v_fouls := v_fouls + 1;
    ELSIF p_type = 'yellow_card' THEN
      v_yellows := v_yellows + 1;
    ELSIF p_type = 'red_card' THEN
      v_reds := v_reds + 1;
    ELSIF p_type = 'offside' THEN
      v_offsides := v_offsides + 1;
    ELSIF p_type = 'shot_on_target' THEN
      v_shots_on := v_shots_on + 1;
    ELSIF p_type = 'shot_off_target' THEN
      v_shots_off := v_shots_off + 1;
    END IF;

    -- Serialize back to JSON
    v_team_stats := jsonb_build_object(
      'goals', v_goals,
      'corners', v_corners,
      'fouls', v_fouls,
      'yellow_cards', v_yellows,
      'red_cards', v_reds,
      'offsides', v_offsides,
      'shots_on_target', v_shots_on,
      'shots_off_target', v_shots_off
    );

    IF v_team = 'team_a' THEN
      v_state := jsonb_set(v_state, '{team_a_stats}', v_team_stats);
    ELSE
      v_state := jsonb_set(v_state, '{team_b_stats}', v_team_stats);
    END IF;

  END IF;

  ---------------------------------------------------------------------------
  -- 5. Set UI Last Event Helper (for overlays/tickers)
  ---------------------------------------------------------------------------
  IF p_type NOT IN ('match_start', 'match_pause', 'match_resume', 'half_time', 'full_time') THEN
     v_state := jsonb_set(v_state, '{last_event_text}', to_jsonb(p_type));
  END IF;

  ---------------------------------------------------------------------------
  -- 6. Insert Log and Update Snapshot
  ---------------------------------------------------------------------------
  INSERT INTO public.ls_events(match_id, sport, type, payload)
  VALUES (p_match_id, 'football', p_type, p_payload);

  UPDATE public.ls_match_state
  SET state = v_state,
      updated_at = now()
  WHERE match_id = p_match_id;

END;
$$;

files.supabase/migrations/0019_badminton_engin:
-- Migration: Phase 5 Badminton Engine
-- Replaces the stub rpc_process_badminton with full BWF-compliant scoring logic

CREATE OR REPLACE FUNCTION public.rpc_process_badminton(
  p_match_id UUID,
  p_type     TEXT,
  p_payload  JSONB
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_state          JSONB;
  v_is_paused      BOOLEAN;

  -- Current game context
  v_current_game   INT;
  v_game_key       TEXT;
  v_score_a        INT;
  v_score_b        INT;
  v_server         TEXT;
  v_games_won_a    INT;
  v_games_won_b    INT;
  v_match_type     TEXT;

  -- Point winner
  v_point_winner   TEXT;       -- 'team_a' | 'team_b'
  v_new_score_a    INT;
  v_new_score_b    INT;
  v_winner_score   INT;
  v_loser_score    INT;
  v_game_won       BOOLEAN;
  v_server_score   INT;        -- score of new server (for serving side calc)
BEGIN
  -- 1. Lock and load current state
  SELECT state, is_paused INTO v_state, v_is_paused
  FROM public.ls_match_state
  WHERE match_id = p_match_id
  FOR UPDATE;

  -- 2. Initialize state if NULL
  IF v_state IS NULL OR v_state = 'null'::jsonb THEN
    v_state := '{
      "match_type": "singles",
      "status": "scheduled",
      "current_game": 1,
      "scores": {
        "g1": {"team_a": 0, "team_b": 0},
        "g2": {"team_a": 0, "team_b": 0},
        "g3": {"team_a": 0, "team_b": 0}
      },
      "games_won": {"team_a": 0, "team_b": 0},
      "server": "team_a",
      "server_player_id": null,
      "serving_side": "right"
    }'::jsonb;
  END IF;

  -- Extract frequently used fields
  v_current_game := COALESCE((v_state->>'current_game')::int, 1);
  v_game_key     := 'g' || v_current_game;
  v_server       := COALESCE(v_state->>'server', 'team_a');
  v_games_won_a  := COALESCE((v_state->'games_won'->>'team_a')::int, 0);
  v_games_won_b  := COALESCE((v_state->'games_won'->>'team_b')::int, 0);
  v_match_type   := COALESCE(v_state->>'match_type', 'singles');

  v_score_a := COALESCE((v_state->'scores'->v_game_key->>'team_a')::int, 0);
  v_score_b := COALESCE((v_state->'scores'->v_game_key->>'team_b')::int, 0);

  ---------------------------------------------------------------------------
  -- 3. Event Routing
  ---------------------------------------------------------------------------

  IF p_type = 'match_start' THEN
    -- Set up who serves first and match type from payload
    v_state := jsonb_set(v_state, '{status}', '"live"');

    IF p_payload->>'match_type' IS NOT NULL THEN
      v_state := jsonb_set(v_state, '{match_type}', to_jsonb(p_payload->>'match_type'));
    END IF;

    IF p_payload->>'first_server' IS NOT NULL THEN
      v_state := jsonb_set(v_state, '{server}', to_jsonb(p_payload->>'first_server'));
    END IF;

    -- First serve is always from right service court
    v_state := jsonb_set(v_state, '{serving_side}', '"right"');
    v_state := jsonb_set(v_state, '{last_event_text}', '"match_start"');

  ---------------------------------------------------------------------------
  ELSIF p_type = 'point' OR p_type = 'service_fault' THEN
    -- Determine point winner
    IF p_type = 'service_fault' THEN
      -- Fault by current server → opponent wins the point
      IF v_server = 'team_a' THEN
        v_point_winner := 'team_b';
      ELSE
        v_point_winner := 'team_a';
      END IF;
    ELSE
      v_point_winner := COALESCE(p_payload->>'team', v_server);
    END IF;

    -- Increment score for winner
    IF v_point_winner = 'team_a' THEN
      v_new_score_a := v_score_a + 1;
      v_new_score_b := v_score_b;
    ELSE
      v_new_score_a := v_score_a;
      v_new_score_b := v_score_b + 1;
    END IF;

    -- Write new scores into state
    v_state := jsonb_set(v_state, ARRAY['scores', v_game_key, 'team_a'], to_jsonb(v_new_score_a));
    v_state := jsonb_set(v_state, ARRAY['scores', v_game_key, 'team_b'], to_jsonb(v_new_score_b));

    -- Service switches to the point winner (BWF rally point rule)
    v_server := v_point_winner;
    v_state  := jsonb_set(v_state, '{server}', to_jsonb(v_server));

    -- Serving side: determined by NEW server's current score
    -- Right court = even score; Left court = odd score
    IF v_server = 'team_a' THEN
      v_server_score := v_new_score_a;
    ELSE
      v_server_score := v_new_score_b;
    END IF;

    IF (v_server_score % 2) = 0 THEN
      v_state := jsonb_set(v_state, '{serving_side}', '"right"');
    ELSE
      v_state := jsonb_set(v_state, '{serving_side}', '"left"');
    END IF;

    -- Optional: update server_player_id from payload (doubles)
    IF p_payload->>'player_id' IS NOT NULL THEN
      v_state := jsonb_set(v_state, '{server_player_id}', to_jsonb(p_payload->>'player_id'));
    END IF;

    -- -----------------------------------------------------------------------
    -- Check for game win (BWF rules):
    --   • First to 21, win by 2
    --   • At 29-all, next point wins (cap 30)
    -- -----------------------------------------------------------------------
    v_game_won := false;
    IF v_point_winner = 'team_a' THEN
      v_winner_score := v_new_score_a;
      v_loser_score  := v_new_score_b;
    ELSE
      v_winner_score := v_new_score_b;
      v_loser_score  := v_new_score_a;
    END IF;

    IF (v_winner_score >= 21 AND (v_winner_score - v_loser_score) >= 2)
       OR v_winner_score = 30 THEN
      v_game_won := true;
    END IF;

    IF v_game_won THEN
      -- Increment games won
      IF v_point_winner = 'team_a' THEN
        v_games_won_a := v_games_won_a + 1;
        v_state := jsonb_set(v_state, '{games_won, team_a}', to_jsonb(v_games_won_a));
      ELSE
        v_games_won_b := v_games_won_b + 1;
        v_state := jsonb_set(v_state, '{games_won, team_b}', to_jsonb(v_games_won_b));
      END IF;

      -- Check if match is over (first to 2 games wins)
      IF v_games_won_a = 2 OR v_games_won_b = 2 THEN
        v_state := jsonb_set(v_state, '{status}', '"completed"');
        v_state := jsonb_set(v_state, '{last_event_text}', '"match_end"');
      ELSE
        -- Advance to next game: interval state
        v_state := jsonb_set(v_state, '{current_game}', to_jsonb(v_current_game + 1));
        v_state := jsonb_set(v_state, '{status}', '"interval"');
        v_state := jsonb_set(v_state, '{last_event_text}', '"game_won"');
        -- Server in next game: the team that lost the previous game serves first (BWF rule
        -- is actually the winner serves first in the next game if they won) — winner serves
        IF v_point_winner = 'team_a' THEN
          v_state := jsonb_set(v_state, '{server}', '"team_a"');
        ELSE
          v_state := jsonb_set(v_state, '{server}', '"team_b"');
        END IF;
        v_state := jsonb_set(v_state, '{serving_side}', '"right"');
      END IF;
    ELSE
      v_state := jsonb_set(v_state, '{last_event_text}', '"point"');
    END IF;

    -- Mid-game interval check (at 11 points in the deciding game 3, or first to 11 each game)
    IF NOT v_game_won 
       AND (v_new_score_a = 11 OR v_new_score_b = 11)
       AND (v_new_score_a + v_new_score_b) <= 11 THEN
      -- First to reach 11 triggers interval (only once per game)
      v_state := jsonb_set(v_state, '{status}', '"interval"');
      v_state := jsonb_set(v_state, '{last_event_text}', '"interval"');
    END IF;

  ---------------------------------------------------------------------------
  ELSIF p_type = 'game_start' THEN
    -- Resume from interval (admin confirms players ready)
    v_state := jsonb_set(v_state, '{status}', '"live"');
    v_state := jsonb_set(v_state, '{last_event_text}', '"game_start"');

  ---------------------------------------------------------------------------
  ELSIF p_type = 'let' THEN
    -- Let: rally replayed, no score change
    v_state := jsonb_set(v_state, '{last_event_text}', '"let"');

  ---------------------------------------------------------------------------
  ELSIF p_type = 'match_end' THEN
    v_state := jsonb_set(v_state, '{status}', '"completed"');
    v_state := jsonb_set(v_state, '{last_event_text}', '"match_end"');

  END IF;

  ---------------------------------------------------------------------------
  -- 4. Log event and update snapshot
  ---------------------------------------------------------------------------
  INSERT INTO public.ls_events(match_id, sport, type, payload)
  VALUES (p_match_id, 'badminton', p_type, p_payload);

  UPDATE public.ls_match_state
  SET state      = v_state,
      updated_at = now()
  WHERE match_id = p_match_id;

END;
$$;

files.supabase/migrations/0021_fix_rls_compreh:
-- Comprehensive RLS fix: ensure admin write access works for authenticated users.

-- 1. Redefine is_admin() with robust fallbacks
CREATE OR REPLACE FUNCTION public.is_admin()
RETURNS boolean
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_role text;
BEGIN
  -- Check profiles table first
  SELECT role INTO v_role
  FROM public.profiles
  WHERE id = auth.uid();

  IF v_role = 'admin' THEN
    RETURN true;
  END IF;

  -- Fallback: check JWT claims
  IF coalesce(current_setting('request.jwt.claims', true)::json->>'role', '') = 'admin' THEN
    RETURN true;
  END IF;
  IF coalesce(current_setting('request.jwt.claims', true)::json->'app_metadata'->>'role', '') = 'admin' THEN
    RETURN true;
  END IF;
  IF coalesce(current_setting('request.jwt.claims', true)::json->'user_metadata'->>'role', '') = 'admin' THEN
    RETURN true;
  END IF;

  RETURN false;
END;
$$;

-- 2. Ensure every existing auth user has a profile row marked admin
INSERT INTO public.profiles (id, email, role)
SELECT id, coalesce(email, ''), 'admin'
FROM auth.users
ON CONFLICT (id) DO UPDATE SET role = 'admin';

-- 3. Ensure ls_tournament_teams has admin write + public read policies
DROP POLICY IF EXISTS "Public Read" ON public.ls_tournament_teams;
CREATE POLICY "Public Read" ON public.ls_tournament_teams FOR SELECT USING (true);

DROP POLICY IF EXISTS "Admin Write" ON public.ls_tournament_teams;
CREATE POLICY "Admin Write" ON public.ls_tournament_teams
  FOR ALL TO authenticated
  USING (public.is_admin())
  WITH CHECK (public.is_admin());

