  v_team_stats JSONB;
  v_goals INT;
  v_corners INT;
  v_fouls INT;
  v_yellows INT;
  v_reds INT;
  v_offsides INT;
  v_shots_on INT;
  v_shots_off INT;
  v_goal_kicks INT;
  v_throw_ins INT;
  v_free_kicks INT;
  
  -- Clock
  v_clock_running BOOLEAN;
  v_last_start_time TEXT;
  v_elapsed_seconds INT;
  
  -- Event
  v_event JSONB;
  v_events JSONB;
  v_event_id TEXT;
  v_penalties JSONB;
  v_penalty_order INT;
BEGIN
  -- 1. Lock and load current state
  SELECT state, is_paused INTO v_state, v_is_paused
  FROM public.ls_match_state
  WHERE match_id = p_match_id
  FOR UPDATE;

  -- 2. Initialize state if NULL
