                <button onClick={() => openEdit(player)} className="btn-secondary text-xs !py-1.5 !px-2.5">
                  Edit
                </button>
                <button onClick={() => handleDelete(player.id)} className="btn-danger text-xs !py-1.5 !px-2.5">
                  Delete
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

