}

/* ── Innings end reasons ──────────────────────── */

export type InningsEndReason = "all_out" | "overs_complete" | "target_reached" | "declared";

/* ── Live Match State (stored in ls_match_state.state jsonb) ──── */

export interface CricketMatchState {
